const CATEGORY_ICONS = {
  "HAMBURGUESA ARTESANAL": "🍔",
  "TRADICIONAL AHUMADA": "🔥",
  "APANADA DE POLLO": "🍗",
  "PERROS CALIENTES": "🌭",
  SALCHIPAPAS: "🍟",
};

function POSView({ products, cart, updateQty, customCart, updateCustomLineQty, customizing, setCustomizing, addCustomLine, activeCategory, setActiveCategory, isDomicilio, setIsDomicilio }) {
  const categories = CATEGORIES.map((c) => c.toUpperCase());
  const filtered = products.filter((p) => p.category.toUpperCase() === activeCategory);

  return (
    <div style={{ padding: "0 16px" }}>
      <div style={{ display: "flex", gap: 8, marginTop: 8, marginBottom: 14 }}>
        <button
          onClick={() => setIsDomicilio(false)}
          style={{ flex: 1, padding: "14px 0", borderRadius: 10, border: "none", background: !isDomicilio ? ORANGE : "#1a1a1a", color: !isDomicilio ? "#fff" : "#999", fontWeight: 700, fontSize: 14.5, display: "flex", alignItems: "center", justifyContent: "center", gap: 8 }}
        >
          🏪 En el local
        </button>
        <button
          onClick={() => setIsDomicilio(true)}
          style={{ flex: 1, padding: "14px 0", borderRadius: 10, border: "none", background: isDomicilio ? ORANGE : "#1a1a1a", color: isDomicilio ? "#fff" : "#999", fontWeight: 700, fontSize: 14.5, display: "flex", alignItems: "center", justifyContent: "center", gap: 8 }}
        >
          🛵 Domicilio
        </button>
      </div>

      <div style={{ display: "flex", gap: 6, padding: "0 0 16px" }}>
        {categories.map((c) => (
          <button
            key={c}
            onClick={() => setActiveCategory(c)}
            title={c}
            style={{
              flex: 1,
              minWidth: 0,
              padding: "14px 0",
              borderRadius: 10,
              border: "none",
              background: activeCategory === c ? ORANGE : "#1a1a1a",
              color: activeCategory === c ? "#fff" : "#999",
              display: "flex",
              alignItems: "center",
              justifyContent: "center",
            }}
          >
            <span style={{ fontSize: 22, lineHeight: 1 }}>{CATEGORY_ICONS[c] || "🍴"}</span>
          </button>
        ))}
      </div>

      {filtered.length === 0 && (
        <div style={{ color: "#666", textAlign: "center", padding: "40px 0" }}>No hay productos en esta categoría.</div>
      )}

      {filtered.length > 0 && (
        <div style={{ color: "#999", fontSize: 12, fontWeight: 700, letterSpacing: 1, marginBottom: 10 }}>
          {activeCategory}
        </div>
      )}

      {filtered.length > 0 && (
        <div className="app-product-grid">
          {filtered.map((p) => (
            <ProductCard
              key={p.id}
              product={p}
              cart={cart}
              updateQty={updateQty}
              customLines={customCart.filter((l) => l.productId === p.id)}
              updateCustomLineQty={updateCustomLineQty}
              onRequestCustom={(mode) => setCustomizing({ product: p, mode })}
            />
          ))}
        </div>
      )}

      {customizing && (
        <RemovableIngredientsModal
          product={customizing.product}
          mode={customizing.mode}
          onCancel={() => setCustomizing(null)}
          onConfirm={(sin) => {
            addCustomLine(customizing.product, customizing.mode, sin);
            setCustomizing(null);
          }}
        />
      )}
    </div>
  );
}

function RemovableIngredientsModal({ product, mode, onCancel, onConfirm }) {
  const [checked, setChecked] = useState([]);

  function toggle(opt) {
    setChecked((prev) => (prev.includes(opt) ? prev.filter((o) => o !== opt) : [...prev, opt]));
  }

  return (
    <div style={{ position: "absolute", inset: 0, zIndex: 500, background: "rgba(0,0,0,0.6)", display: "flex", alignItems: "flex-end" }} onClick={onCancel}>
      <div
        style={{ background: "#161616", borderTopLeftRadius: 20, borderTopRightRadius: 20, padding: "20px 18px 24px", width: "100%" }}
        onClick={(e) => e.stopPropagation()}
      >
        <div style={{ fontWeight: 800, fontSize: 16, marginBottom: 4 }}>{product.name}</div>
        <div style={{ color: "#999", fontSize: 13, marginBottom: 16 }}>¿El cliente quiere quitar algún ingrediente?</div>

        <div style={{ display: "flex", flexDirection: "column", gap: 4, marginBottom: 18 }}>
          {(product.removable || []).map((opt) => (
            <button
              key={opt}
              onClick={() => toggle(opt)}
              style={{
                display: "flex",
                alignItems: "center",
                gap: 12,
                background: "#1e1e1e",
                border: "none",
                borderRadius: 10,
                padding: "13px 14px",
                color: "#fff",
                fontSize: 14.5,
                fontWeight: 600,
                textAlign: "left",
              }}
            >
              <div
                style={{
                  width: 22,
                  height: 22,
                  borderRadius: 6,
                  border: `2px solid ${checked.includes(opt) ? ORANGE : "#555"}`,
                  background: checked.includes(opt) ? ORANGE : "transparent",
                  display: "flex",
                  alignItems: "center",
                  justifyContent: "center",
                  flexShrink: 0,
                }}
              >
                {checked.includes(opt) && <Check size={15} color="#fff" />}
              </div>
              {opt}
            </button>
          ))}
        </div>

        <div style={{ display: "flex", gap: 10 }}>
          <button onClick={onCancel} style={{ flex: 1, background: "#262626", border: "none", borderRadius: 12, padding: "15px", color: "#ccc", fontWeight: 700, fontSize: 15 }}>
            Cancelar
          </button>
          <button onClick={() => onConfirm(checked)} style={{ flex: 2, background: ORANGE, border: "none", borderRadius: 12, padding: "15px", color: "#fff", fontWeight: 800, fontSize: 15 }}>
            Agregar {mode === "combo" ? "Combo" : ""}
          </button>
        </div>
      </div>
    </div>
  );
}

function ProductCard({ product: p, cart, updateQty, customLines, updateCustomLineQty, onRequestCustom }) {
  const normalKey = `${p.id}::normal`;
  const comboKey = `${p.id}::combo`;
  const hasRemovable = p.removable && p.removable.length > 0;
  const normalLines = (customLines || []).filter((l) => l.mode === "normal");
  const comboLines = (customLines || []).filter((l) => l.mode === "combo");

  return (
    <div style={{ background: "#141414", borderRadius: 16, padding: 12, display: "flex", flexDirection: "column" }}>
      <img src={p.image} alt={p.name} style={{ width: "100%", aspectRatio: "1", borderRadius: 12, objectFit: "cover", marginBottom: 10 }} />
      <div style={{ fontWeight: 700, fontSize: 15, lineHeight: 1.25 }}>{p.name}</div>
      <div style={{ color: "#999", fontSize: 12.5, marginTop: 3, marginBottom: 10, display: "-webkit-box", WebkitLineClamp: 2, WebkitBoxOrient: "vertical", overflow: "hidden" }}>{p.desc}</div>

      {hasRemovable ? (
        <AddRow label="Normal" price={p.price} onAdd={() => onRequestCustom("normal")} />
      ) : (
        <PriceRow label="Normal" price={p.price} qty={cart[normalKey] || 0} onDec={() => updateQty(normalKey, -1)} onInc={() => updateQty(normalKey, 1)} />
      )}
      {normalLines.length > 0 && (
        <div style={{ marginTop: 6, display: "flex", flexDirection: "column", gap: 6 }}>
          {normalLines.map((l) => (
            <CustomLineRow key={l.lineId} line={l} onDec={() => updateCustomLineQty(l.lineId, -1)} onInc={() => updateCustomLineQty(l.lineId, 1)} />
          ))}
        </div>
      )}

      {p.comboPrice != null && (
        <>
          {hasRemovable ? (
            <AddRow label="+ papas y gaseosa" price={p.comboPrice} combo onAdd={() => onRequestCustom("combo")} />
          ) : (
            <PriceRow label="+ papas y gaseosa" price={p.comboPrice} qty={cart[comboKey] || 0} onDec={() => updateQty(comboKey, -1)} onInc={() => updateQty(comboKey, 1)} combo />
          )}
          {comboLines.length > 0 && (
            <div style={{ marginTop: 6, display: "flex", flexDirection: "column", gap: 6 }}>
              {comboLines.map((l) => (
                <CustomLineRow key={l.lineId} line={l} onDec={() => updateCustomLineQty(l.lineId, -1)} onInc={() => updateCustomLineQty(l.lineId, 1)} />
              ))}
            </div>
          )}
        </>
      )}
    </div>
  );
}

