function PrinterSettingsView({ account, onSave, onBack }) {
  const [autoEnabled, setAutoEnabled] = useState(account?.printerAutoEnabled || false);
  const [serviceUUID, setServiceUUID] = useState(account?.printerServiceUUID || "000018f0-0000-1000-8000-00805f9b34fb");
  const [charUUID, setCharUUID] = useState(account?.printerCharUUID || "00002af1-0000-1000-8000-00805f9b34fb");
  const [testStatus, setTestStatus] = useState("");

  async function save(next) {
    await onSave({ ...account, printerAutoEnabled: next.autoEnabled ?? autoEnabled, printerServiceUUID: next.serviceUUID ?? serviceUUID, printerCharUUID: next.charUUID ?? charUUID });
  }

  async function handleTestPrint() {
    setTestStatus("printing");
    try {
      const testSale = {
        id: "test" + Date.now(),
        timestamp: new Date().toISOString(),
        domicilio: false,
        items: [{ name: "Ticket de prueba", qty: 1, price: 0, sin: [] }],
        total: 0,
      };
      await printTicketBluetooth(testSale, { ...account, printerServiceUUID: serviceUUID, printerCharUUID: charUUID });
      setTestStatus("ok");
    } catch (err) {
      setTestStatus(err.message || "No se pudo imprimir.");
    }
  }

  return (
    <div style={{ padding: "16px 18px" }}>
      <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 20 }}>
        <button onClick={onBack} style={{ background: "none", border: "none", color: "#fff" }}><ChevronLeft size={22} /></button>
        <h2 style={{ margin: 0 }}>🖨️ Impresora Bluetooth</h2>
      </div>

      <div style={{ background: "#1e3a8a", borderRadius: 12, padding: 14, marginBottom: 18, color: "#dbeafe", fontSize: 13, lineHeight: 1.4 }}>
        Solo funciona en <b>Chrome para Android</b>, con la impresora ya emparejada en Bluetooth del celular. En iPhone no es posible (Apple no lo permite en Safari).
      </div>

      <button
        onClick={() => {
          const next = !autoEnabled;
          setAutoEnabled(next);
          save({ autoEnabled: next });
        }}
        style={{ width: "100%", ...menuItemStyle, marginBottom: 18 }}
      >
        <span>Imprimir automáticamente al cobrar</span>
        <span style={{ color: autoEnabled ? "#4ade80" : "#666", fontWeight: 800 }}>{autoEnabled ? "Activada" : "Desactivada"}</span>
      </button>

      <div style={{ fontWeight: 700, fontSize: 15, marginBottom: 6 }}>Configuración avanzada</div>
      <div style={{ color: "#999", fontSize: 13, marginBottom: 12 }}>
        Solo cámbialo si tu impresora no imprime con los valores por defecto (varía según la marca/modelo).
      </div>
      <Field label="UUID del servicio">
        <input style={inputStyle} value={serviceUUID} onChange={(e) => setServiceUUID(e.target.value)} onBlur={() => save({})} />
      </Field>
      <Field label="UUID de la característica">
        <input style={inputStyle} value={charUUID} onChange={(e) => setCharUUID(e.target.value)} onBlur={() => save({})} />
      </Field>

      <button
        onClick={handleTestPrint}
        disabled={testStatus === "printing"}
        style={{ ...primaryBtn, width: "100%", marginTop: 8, display: "flex", alignItems: "center", justifyContent: "center", gap: 8 }}
      >
        🖨️ {testStatus === "printing" ? "Conectando..." : "Imprimir ticket de prueba"}
      </button>
      {testStatus === "ok" && <div style={{ color: "#4ade80", fontSize: 13, textAlign: "center", marginTop: 8 }}>✓ Impreso correctamente.</div>}
      {testStatus && testStatus !== "ok" && testStatus !== "printing" && (
        <div style={{ color: "#f87171", fontSize: 13, textAlign: "center", marginTop: 8 }}>{testStatus}</div>
      )}
    </div>
  );
}

function StatsView({ sales, products, pedidos, onBack }) {
  const [period, setPeriod] = useState("day"); // day | week | month

  const buckets = {};
  sales.forEach((s) => {
    let key, label;
    if (period === "day") {
      key = s.dateKey;
      const d = new Date(s.dateKey + "T00:00:00");
      label = d.toLocaleDateString("es-CO", { day: "2-digit", month: "2-digit" });
    } else if (period === "week") {
      key = weekKeyOf(s.dateKey);
      const d = new Date(key + "T00:00:00");
      label = "Sem " + d.toLocaleDateString("es-CO", { day: "2-digit", month: "2-digit" });
    } else {
      key = monthKeyOf(s.dateKey);
      const [y, m] = key.split("-");
      label = `${MONTH_NAMES_ES[parseInt(m, 10) - 1]} ${y.slice(2)}`;
    }
    if (!buckets[key]) buckets[key] = { key, label, total: 0, count: 0 };
    buckets[key].total += s.total;
    buckets[key].count += 1;
  });

  const limit = period === "day" ? 14 : period === "week" ? 10 : 12;
  const data = Object.values(buckets)
    .sort((a, b) => (a.key < b.key ? -1 : 1))
    .slice(-limit);

  const totalRevenue = data.reduce((s, d) => s + d.total, 0);
  const totalCount = data.reduce((s, d) => s + d.count, 0);
  const avgTicket = totalCount > 0 ? totalRevenue / totalCount : 0;

  // Tendencia: compara el último período contra el anterior
  const last = data[data.length - 1];
  const prev = data[data.length - 2];
  const trendPct = last && prev && prev.total > 0 ? Math.round(((last.total - prev.total) / prev.total) * 100) : null;

  // Proyección simple: promedio de los cambios recientes, aplicado al último valor
  let chartData = data;
  if (data.length >= 2) {
    const deltas = [];
    for (let i = 1; i < data.length; i++) deltas.push(data[i].total - data[i - 1].total);
    const avgDelta = deltas.reduce((a, b) => a + b, 0) / deltas.length;
    const projectedValue = Math.max(0, Math.round((data[data.length - 1].total + avgDelta) / 100) * 100);
    chartData = [...data, { key: "proj", label: "Proyección", total: projectedValue, count: 0, isProjection: true }];
  }

  // Productos más vendidos (histórico completo)
  const productAgg = {};
  sales.forEach((s) =>
    s.items.forEach((it) => {
      const name = it.name.replace(" (Combo)", "");
      productAgg[name] = (productAgg[name] || 0) + it.qty;
    })
  );
  const topProducts = Object.entries(productAgg)
    .map(([name, qty]) => ({ name, qty }))
    .sort((a, b) => b.qty - a.qty)
    .slice(0, 5);
  const maxQty = topProducts[0]?.qty || 1;

  // Ventas por categoría
  const categoryAgg = {};
  sales.forEach((s) =>
    s.items.forEach((it) => {
      const prod = (products || []).find((p) => p.id === it.productId);
      const cat = prod?.category || "Otros";
      categoryAgg[cat] = (categoryAgg[cat] || 0) + it.qty * it.price;
    })
  );
  const categoryData = Object.entries(categoryAgg)
    .map(([cat, total]) => ({ cat, total }))
    .sort((a, b) => b.total - a.total);

  // Domicilios por mes (últimos 6 meses)
  const domMonthAgg = {};
  sales
    .filter((s) => s.domicilio)
    .forEach((s) => {
      const mk = monthKeyOf(s.dateKey);
      domMonthAgg[mk] = (domMonthAgg[mk] || 0) + 1;
    });
  const domData = Object.entries(domMonthAgg)
    .map(([mk, count]) => {
      const [y, m] = mk.split("-");
      return { key: mk, label: `${MONTH_NAMES_ES[parseInt(m, 10) - 1]} ${y.slice(2)}`, count };
    })
    .sort((a, b) => (a.key < b.key ? -1 : 1))
    .slice(-6);

  const periods = [
    { key: "day", label: "Por día" },
    { key: "week", label: "Por semana" },
    { key: "month", label: "Por mes" },
  ];

  return (
    <div style={{ padding: "16px 18px" }}>
      <div style={{ display: "flex", alignItems: "center", gap: 10, marginBottom: 18 }}>
        <button onClick={onBack} style={{ background: "#1a1a1a", border: "none", borderRadius: 10, width: 40, height: 40, color: "#fff", display: "flex", alignItems: "center", justifyContent: "center", flexShrink: 0 }}>
          <ChevronLeft size={24} />
        </button>
        <h2 style={{ margin: 0, fontSize: 19 }}>📊 Estadísticas del negocio</h2>
      </div>

      {/* Tarjeta premium de resumen */}
      <div
        style={{
          background: "linear-gradient(135deg, #2a1608 0%, #1a0f05 60%, #120b04 100%)",
          border: "1px solid rgba(245,130,31,0.3)",
          borderRadius: 20,
          padding: 20,
          marginBottom: 16,
          boxShadow: "0 8px 24px rgba(245,130,31,0.12)",
        }}
      >
        <div style={{ color: "#f0c9a0", fontSize: 12, fontWeight: 700, letterSpacing: 1.5, marginBottom: 6 }}>INGRESOS DEL PERÍODO</div>
        <div style={{ display: "flex", alignItems: "baseline", gap: 10 }}>
          <div style={{ fontSize: 30, fontWeight: 800, background: "linear-gradient(90deg, #fff, #ffd9ad)", WebkitBackgroundClip: "text", WebkitTextFillColor: "transparent", backgroundClip: "text" }}>
            {money(totalRevenue)}
          </div>
          {trendPct !== null && (
            <div style={{ color: trendPct >= 0 ? "#4ade80" : "#f87171", fontWeight: 700, fontSize: 13, display: "flex", alignItems: "center", gap: 3 }}>
              {trendPct >= 0 ? <ArrowDown size={13} style={{ transform: "rotate(180deg)" }} /> : <ArrowDown size={13} />}
              {Math.abs(trendPct)}%
            </div>
          )}
        </div>
        <div style={{ color: "#a88a63", fontSize: 12, marginTop: 4 }}>{totalCount} ventas · ticket promedio {money(Math.round(avgTicket))}</div>
      </div>

      <div style={{ display: "flex", gap: 8, marginBottom: 16 }}>
        {periods.map((p) => (
          <button
            key={p.key}
            onClick={() => setPeriod(p.key)}
            style={{
              flex: 1,
              padding: "12px 0",
              borderRadius: 10,
              border: "none",
              background: period === p.key ? ORANGE : "#1a1a1a",
              color: period === p.key ? "#fff" : "#999",
              fontWeight: 700,
              fontSize: 13.5,
            }}
          >
            {p.label}
          </button>
        ))}
      </div>

      {chartData.length === 0 ? (
        <div style={{ color: "#666", textAlign: "center", padding: "40px 0", fontSize: 15 }}>
          Aún no hay ventas suficientes para mostrar esta gráfica.
        </div>
      ) : (
        <div style={{ background: "#141414", borderRadius: 16, padding: "16px 8px 8px", marginBottom: 8 }}>
          <ResponsiveContainer width="100%" height={240}>
            <BarChart data={chartData} margin={{ top: 4, right: 8, left: -12, bottom: 4 }}>
              <defs>
                <linearGradient id="barFill" x1="0" y1="0" x2="0" y2="1">
                  <stop offset="0%" stopColor="#ffb347" />
                  <stop offset="100%" stopColor="#c85f0f" />
                </linearGradient>
              </defs>
              <CartesianGrid strokeDasharray="3 3" stroke="#262626" vertical={false} />
              <XAxis dataKey="label" stroke="#888" fontSize={10.5} tickLine={false} />
              <YAxis stroke="#888" fontSize={11} tickLine={false} width={44} tickFormatter={(v) => (v >= 1000 ? `${Math.round(v / 1000)}k` : v)} />
              <Tooltip
                contentStyle={{ background: "#1a1a1a", border: "1px solid #333", borderRadius: 10, color: "#fff" }}
                labelStyle={{ color: "#ccc" }}
                formatter={(value, name, props) => [money(value), props.payload.isProjection ? "Proyección estimada" : "Ventas"]}
              />
              <Bar dataKey="total" radius={[6, 6, 0, 0]}>
                {chartData.map((d, i) => (
                  <Cell key={i} fill={d.isProjection ? "#6d7bff" : "url(#barFill)"} fillOpacity={d.isProjection ? 0.55 : 1} stroke={d.isProjection ? "#6d7bff" : "none"} strokeDasharray={d.isProjection ? "4 3" : "0"} />
                ))}
              </Bar>
            </BarChart>
          </ResponsiveContainer>
        </div>
      )}
      {chartData.some((d) => d.isProjection) && (
        <div style={{ color: "#8891ff", fontSize: 12, textAlign: "center", marginBottom: 20 }}>
          🔮 La barra punteada es una proyección estimada según tu tendencia reciente.
        </div>
      )}

      {/* Productos más vendidos */}
      <div style={{ background: "#141414", borderRadius: 16, padding: 18, marginBottom: 16 }}>
        <div style={{ fontWeight: 800, fontSize: 15, marginBottom: 14 }}>🏆 Productos más vendidos</div>
        {topProducts.length === 0 && <div style={{ color: "#666", fontSize: 14, textAlign: "center", padding: "10px 0" }}>Aún no hay ventas registradas.</div>}
        {topProducts.map((p, i) => (
          <div key={p.name} style={{ marginBottom: i === topProducts.length - 1 ? 0 : 12 }}>
            <div style={{ display: "flex", justifyContent: "space-between", fontSize: 13.5, marginBottom: 4 }}>
              <span style={{ fontWeight: 600 }}>
                <span style={{ color: ORANGE, fontWeight: 800 }}>#{i + 1}</span> {p.name}
              </span>
              <span style={{ color: "#999", fontWeight: 700 }}>{p.qty} und.</span>
            </div>
            <div style={{ background: "#262626", borderRadius: 999, height: 8, overflow: "hidden" }}>
              <div style={{ width: `${(p.qty / maxQty) * 100}%`, height: "100%", background: "linear-gradient(90deg, #ffb347, #f5821f)", borderRadius: 999 }} />
            </div>
          </div>
        ))}
      </div>

      {/* Ventas por categoría */}
      {categoryData.length > 0 && (
        <div style={{ background: "#141414", borderRadius: 16, padding: "18px 8px 8px", marginBottom: 16 }}>
          <div style={{ fontWeight: 800, fontSize: 15, marginBottom: 6, padding: "0 10px" }}>🍽️ Ventas por categoría</div>
          <ResponsiveContainer width="100%" height={180}>
            <BarChart data={categoryData} layout="vertical" margin={{ top: 4, right: 20, left: 8, bottom: 4 }}>
              <CartesianGrid strokeDasharray="3 3" stroke="#262626" horizontal={false} />
              <XAxis type="number" stroke="#888" fontSize={10.5} tickLine={false} tickFormatter={(v) => (v >= 1000 ? `${Math.round(v / 1000)}k` : v)} />
              <YAxis type="category" dataKey="cat" stroke="#888" fontSize={11.5} tickLine={false} width={110} />
              <Tooltip contentStyle={{ background: "#1a1a1a", border: "1px solid #333", borderRadius: 10, color: "#fff" }} formatter={(value) => [money(value), "Ingresos"]} />
              <Bar dataKey="total" fill={ORANGE} radius={[0, 6, 6, 0]} barSize={18} />
            </BarChart>
          </ResponsiveContainer>
        </div>
      )}

      {/* Domicilios por mes */}
      {domData.length > 0 && (
        <div style={{ background: "#141414", borderRadius: 16, padding: "18px 8px 8px", marginBottom: 8 }}>
          <div style={{ fontWeight: 800, fontSize: 15, marginBottom: 6, padding: "0 10px" }}>🛵 Domicilios por mes</div>
          <ResponsiveContainer width="100%" height={180}>
            <BarChart data={domData} margin={{ top: 4, right: 8, left: -12, bottom: 4 }}>
              <CartesianGrid strokeDasharray="3 3" stroke="#262626" vertical={false} />
              <XAxis dataKey="label" stroke="#888" fontSize={10.5} tickLine={false} />
              <YAxis stroke="#888" fontSize={11} tickLine={false} width={30} allowDecimals={false} />
              <Tooltip contentStyle={{ background: "#1a1a1a", border: "1px solid #333", borderRadius: 10, color: "#fff" }} formatter={(value) => [value, "Domicilios"]} />
              <Bar dataKey="count" fill="#3b82f6" radius={[6, 6, 0, 0]} />
            </BarChart>
          </ResponsiveContainer>
        </div>
      )}
    </div>
  );
}

