function BusinessForm({ account, onSave, onCancel }) {
  const [username, setUsername] = useState(account?.username || "");
  const [newPassword, setNewPassword] = useState("");
  const [workerPin, setWorkerPin] = useState(account?.workerPin || "1234");
  const [error, setError] = useState("");

  function submit() {
    if (!username.trim()) {
      setError("El usuario es obligatorio.");
      return;
    }
    if (!workerPin.trim() || workerPin.trim().length < 4) {
      setError("El PIN de trabajadores debe tener al menos 4 dígitos.");
      return;
    }
    onSave({
      ...account,
      username: username.trim(),
      password: newPassword.trim() ? newPassword : account.password,
      workerPin: workerPin.trim(),
    });
  }

  return (
    <div style={{ padding: "16px 18px" }}>
      <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 16 }}>
        <button onClick={onCancel} style={{ background: "none", border: "none", color: "#fff" }}><ChevronLeft size={22} /></button>
        <h2 style={{ margin: 0 }}>Cuenta y trabajadores</h2>
      </div>

      {error && <div style={{ color: "#f87171", fontSize: 13, marginBottom: 12 }}>{error}</div>}

      <Field label="Usuario"><input style={inputStyle} value={username} onChange={(e) => setUsername(e.target.value)} /></Field>
      <Field label="Nueva contraseña (déjalo vacío para no cambiarla)">
        <input type="password" style={inputStyle} value={newPassword} onChange={(e) => setNewPassword(e.target.value)} placeholder="••••••••" />
      </Field>

      <div style={{ height: 1, background: "#222", margin: "20px 0 16px" }} />
      <div style={{ fontWeight: 700, fontSize: 15, marginBottom: 6 }}>🍳 Acceso para trabajadores</div>
      <div style={{ color: "#999", fontSize: 13, marginBottom: 12 }}>
        Comparte este PIN con tus empleados. Con él eligen su puesto (Cocina o Domiciliario) y entran directo, sin ver ventas ni configuración.
      </div>
      <Field label="PIN de trabajadores">
        <input
          type="tel"
          inputMode="numeric"
          style={{ ...inputStyle, fontSize: 20, letterSpacing: 4, textAlign: "center" }}
          value={workerPin}
          onChange={(e) => setWorkerPin(e.target.value.replace(/\D/g, ""))}
        />
      </Field>

      <button onClick={submit} style={{ ...primaryBtn, width: "100%", marginTop: 8, display: "flex", alignItems: "center", justifyContent: "center", gap: 8 }}>
        <Check size={16} /> Guardar
      </button>
    </div>
  );
}

