function ProductManager({ products, saveProducts, onBack, editing, setEditing, saveError }) {
  if (editing) {
    return (
      <ProductForm
        product={editing === "new" ? null : editing}
        onCancel={() => setEditing(null)}
        onSave={async (p) => {
          let next;
          if (editing === "new") {
            next = [...products, { ...p, id: "p" + Date.now() }];
          } else {
            next = products.map((x) => (x.id === editing.id ? { ...x, ...p } : x));
          }
          await saveProducts(next);
          setEditing(null);
        }}
      />
    );
  }

  return (
    <div style={{ padding: "16px 18px" }}>
      <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 16 }}>
        <button onClick={onBack} style={{ background: "none", border: "none", color: "#fff" }}><ChevronLeft size={22} /></button>
        <h2 style={{ margin: 0 }}>Productos</h2>
      </div>

      {saveError && <div style={{ color: "#f87171", fontSize: 13, marginBottom: 12 }}>{saveError}</div>}

      <button onClick={() => setEditing("new")} style={{ ...primaryBtn, width: "100%", marginBottom: 16, display: "flex", alignItems: "center", justifyContent: "center", gap: 8 }}>
        <Plus size={16} /> Agregar producto
      </button>

      {products.map((p) => (
        <div key={p.id} style={{ display: "flex", gap: 12, background: "#141414", borderRadius: 14, padding: 12, marginBottom: 10, alignItems: "center" }}>
          <img src={p.image} alt={p.name} style={{ width: 50, height: 50, borderRadius: 8, objectFit: "cover" }} />
          <div style={{ flex: 1, minWidth: 0 }}>
            <div style={{ fontWeight: 700, fontSize: 14 }}>{p.name}</div>
            <div style={{ color: "#999", fontSize: 12 }}>{p.category} · {money(p.price)} · stock {p.stock}</div>
          </div>
          <button onClick={() => setEditing(p)} style={{ background: "#2a2a2a", border: "none", borderRadius: 8, width: 34, height: 34, color: "#fff", display: "flex", alignItems: "center", justifyContent: "center" }}>
            <Pencil size={15} />
          </button>
          <button
            onClick={async () => await saveProducts(products.filter((x) => x.id !== p.id))}
            style={{ background: "#2a2a2a", border: "none", borderRadius: 8, width: 34, height: 34, color: "#f87171", display: "flex", alignItems: "center", justifyContent: "center" }}
          >
            <Trash2 size={15} />
          </button>
        </div>
      ))}
    </div>
  );
}

function ProductForm({ product, onSave, onCancel }) {
  const [name, setName] = useState(product?.name || "");
  const [desc, setDesc] = useState(product?.desc || "");
  const [price, setPrice] = useState(product?.price ?? "");
  const [comboPrice, setComboPrice] = useState(product?.comboPrice ?? "");
  const [category, setCategory] = useState(product?.category || CATEGORIES[0]);
  const [image, setImage] = useState(product?.image || "");
  const [stock, setStock] = useState(product?.stock ?? "");
  const [removable, setRemovable] = useState(product?.removable || []);
  const [error, setError] = useState("");

  function toggleRemovable(opt) {
    setRemovable((prev) => (prev.includes(opt) ? prev.filter((o) => o !== opt) : [...prev, opt]));
  }

  function submit() {
    if (!name.trim() || price === "" || isNaN(parseFloat(price))) {
      setError("El nombre y el precio son obligatorios.");
      return;
    }
    onSave({
      name: name.trim(),
      desc: desc.trim(),
      price: parseFloat(price),
      comboPrice: comboPrice === "" ? null : parseFloat(comboPrice),
      category,
      image: image.trim() || "https://images.unsplash.com/photo-1546069901-ba9599a7e63c?w=300&h=300&fit=crop",
      stock: stock === "" ? 0 : parseInt(stock, 10),
      removable,
    });
  }

  return (
    <div style={{ padding: "16px 18px" }}>
      <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 16 }}>
        <button onClick={onCancel} style={{ background: "none", border: "none", color: "#fff" }}><ChevronLeft size={22} /></button>
        <h2 style={{ margin: 0 }}>{product ? "Editar producto" : "Nuevo producto"}</h2>
      </div>

      {error && <div style={{ color: "#f87171", fontSize: 13, marginBottom: 12 }}>{error}</div>}

      {image && (
        <div style={{ display: "flex", justifyContent: "center", marginBottom: 14 }}>
          <img src={image} alt={name} style={{ width: 120, height: 120, borderRadius: 16, objectFit: "cover" }} />
        </div>
      )}
      <div style={{ marginBottom: 14 }}>
        <PhotoPicker label="Subir foto del producto desde el teléfono" onPick={(dataUrl) => setImage(dataUrl)} />
      </div>

      <Field label="Nombre"><input style={inputStyle} value={name} onChange={(e) => setName(e.target.value)} /></Field>
      <Field label="Descripción"><input style={inputStyle} value={desc} onChange={(e) => setDesc(e.target.value)} /></Field>
      <Field label="Precio normal"><input type="number" style={inputStyle} value={price} onChange={(e) => setPrice(e.target.value)} /></Field>
      <Field label="Precio combo (déjalo vacío si no tiene combo)">
        <input type="number" style={inputStyle} value={comboPrice} onChange={(e) => setComboPrice(e.target.value)} />
      </Field>
      <Field label="Stock">
        <input type="number" style={inputStyle} value={stock} onChange={(e) => setStock(e.target.value)} />
      </Field>
      <Field label="Categoría">
        <select style={inputStyle} value={category} onChange={(e) => setCategory(e.target.value)}>
          {CATEGORIES.map((c) => (
            <option key={c} value={c}>{c}</option>
          ))}
        </select>
      </Field>
      <Field label="O pega la URL de una imagen (opcional)">
        <input style={inputStyle} value={isImageSrc(image) && image.startsWith("data:") ? "" : image} onChange={(e) => setImage(e.target.value)} placeholder="https://..." />
      </Field>

      <div style={{ height: 1, background: "#222", margin: "20px 0 16px" }} />
      <div style={{ fontWeight: 700, fontSize: 15, marginBottom: 6 }}>🧾 Personalización del pedido</div>
      <div style={{ color: "#999", fontSize: 13, marginBottom: 12 }}>
        Marca qué ingredientes puede quitar el cliente en este producto. El cajero verá estas opciones al agregarlo a la venta.
      </div>
      <div style={{ display: "flex", flexDirection: "column", gap: 8, marginBottom: 8 }}>
        {REMOVABLE_OPTIONS.map((opt) => (
          <button
            key={opt}
            onClick={() => toggleRemovable(opt)}
            style={{
              display: "flex",
              alignItems: "center",
              gap: 12,
              background: "#1e1e1e",
              border: "none",
              borderRadius: 10,
              padding: "12px 14px",
              color: "#fff",
              fontSize: 14,
              fontWeight: 600,
              textAlign: "left",
            }}
          >
            <div
              style={{
                width: 20,
                height: 20,
                borderRadius: 5,
                border: `2px solid ${removable.includes(opt) ? ORANGE : "#555"}`,
                background: removable.includes(opt) ? ORANGE : "transparent",
                display: "flex",
                alignItems: "center",
                justifyContent: "center",
                flexShrink: 0,
              }}
            >
              {removable.includes(opt) && <Check size={13} color="#fff" />}
            </div>
            {opt}
          </button>
        ))}
      </div>

      <button onClick={submit} style={{ ...primaryBtn, width: "100%", marginTop: 8, display: "flex", alignItems: "center", justifyContent: "center", gap: 8 }}>
        <Check size={16} /> Guardar producto
      </button>
    </div>
  );
}

function InsumosView({ insumos, saveInsumos, movimientos: dailyStats, saveMovimientos: saveDailyStats, historial, saveHistorial, onBack, saveError, account }) {
  const [editing, setEditing] = useState(null); // null | "new" | insumo obj
  const [confirmDeleteId, setConfirmDeleteId] = useState(null);
  const [savedMessage, setSavedMessage] = useState("");
  const [viewingHistory, setViewingHistory] = useState(false);

  if (editing) {
    return (
      <InsumoForm
        insumo={editing === "new" ? null : editing}
        onCancel={() => setEditing(null)}
        onSave={async (data) => {
          let next;
          if (editing === "new") {
            next = [...insumos, { ...data, id: "i" + Date.now() }];
          } else {
            next = insumos.map((x) => (x.id === editing.id ? { ...x, ...data } : x));
          }
          await saveInsumos(next);
          setEditing(null);
        }}
      />
    );
  }

  if (viewingHistory) {
    return <InventoryHistoryView historial={historial} onBack={() => setViewingHistory(false)} />;
  }

  const today = todayKey();
  const todayStats = dailyStats[today] || {};

  function statFor(insumoId) {
    return todayStats[insumoId] || { entradas: 0, salidas: 0 };
  }

  const totalEntradas = insumos.reduce((sum, i) => sum + statFor(i.id).entradas, 0);
  const totalSalidas = insumos.reduce((sum, i) => sum + statFor(i.id).salidas, 0);

  async function bumpEntrada(insumo, delta) {
    const nextStock = Math.max(0, insumo.stock + delta);
    const cur = statFor(insumo.id);
    const nextEntradas = Math.max(0, cur.entradas + delta);
    await saveInsumos(insumos.map((x) => (x.id === insumo.id ? { ...x, stock: nextStock } : x)));
    await saveDailyStats({ ...dailyStats, [today]: { ...todayStats, [insumo.id]: { ...cur, entradas: nextEntradas } } });
  }

  async function bumpSalida(insumo, delta) {
    const cur = statFor(insumo.id);
    const nextSalidas = Math.max(0, cur.salidas + delta);
    await saveDailyStats({ ...dailyStats, [today]: { ...todayStats, [insumo.id]: { ...cur, salidas: nextSalidas } } });
  }

  async function closeDay() {
    const updated = insumos.map((i) => {
      const stat = statFor(i.id);
      const quedan = Math.max(0, i.stock - stat.salidas);
      return { ...i, stock: quedan };
    });

    // Build today's summary, merging with anything already saved earlier today.
    const existingRecord = historial.find((h) => h.dateKey === today);
    const existingItemsById = {};
    (existingRecord?.items || []).forEach((it) => {
      existingItemsById[it.insumoId] = it;
    });
    const newItems = insumos
      .map((i) => {
        const stat = statFor(i.id);
        const prev = existingItemsById[i.id];
        const entradas = (prev?.entradas || 0) + stat.entradas;
        const salidas = (prev?.salidas || 0) + stat.salidas;
        const quedan = Math.max(0, i.stock - stat.salidas);
        return { insumoId: i.id, name: i.name, unit: i.unit, icon: i.icon, entradas, salidas, quedan };
      })
      .filter((it) => it.entradas > 0 || it.salidas > 0);

    let nextHistorial;
    if (newItems.length > 0) {
      const record = { id: existingRecord?.id || "hist" + Date.now(), dateKey: today, timestamp: new Date().toISOString(), items: newItems };
      if (existingRecord) {
        nextHistorial = historial.map((h) => (h.dateKey === today ? record : h));
      } else {
        nextHistorial = [record, ...historial];
      }
      await saveHistorial(nextHistorial);
    }

    await saveInsumos(updated);
    const resetStats = { ...todayStats };
    insumos.forEach((i) => {
      resetStats[i.id] = { entradas: 0, salidas: 0 };
    });
    await saveDailyStats({ ...dailyStats, [today]: resetStats });
    setSavedMessage("Bodega actualizada y guardada en el historial.");
    setTimeout(() => setSavedMessage(""), 4000);
  }

  const dateLabel = new Date().toLocaleDateString("es-CO", { weekday: "long", day: "numeric", month: "long", year: "numeric" });
  const dateLabelCap = dateLabel.charAt(0).toUpperCase() + dateLabel.slice(1);

  return (
    <div style={{ padding: "16px 18px" }}>
      <div style={{ display: "flex", alignItems: "center", gap: 10, marginBottom: 6 }}>
        <button onClick={onBack} style={{ background: "#1a1a1a", border: "none", borderRadius: 10, width: 40, height: 40, color: "#fff", display: "flex", alignItems: "center", justifyContent: "center", flexShrink: 0 }}>
          <ChevronLeft size={24} />
        </button>
        <div style={{ flex: 1 }}>
          <h2 style={{ margin: 0, fontSize: 20 }}>Inventario de hoy</h2>
          <div style={{ color: "#999", fontSize: 14 }}>{dateLabelCap}</div>
        </div>
        <button
          onClick={() => setEditing("new")}
          style={{ background: ORANGE, border: "none", borderRadius: 10, padding: "10px 14px", color: "#fff", fontWeight: 700, fontSize: 13, display: "flex", alignItems: "center", gap: 6, flexShrink: 0 }}
        >
          <Plus size={16} /> Agregar insumo
        </button>
      </div>

      {saveError && <div style={{ color: "#f87171", fontSize: 14, margin: "12px 0" }}>{saveError}</div>}

      <button
        onClick={() => setViewingHistory(true)}
        style={{ width: "100%", background: "#1a1a1a", border: "1px solid #333", borderRadius: 12, padding: "14px", color: "#ccc", fontWeight: 700, fontSize: 14, display: "flex", alignItems: "center", justifyContent: "center", gap: 8, margin: "14px 0" }}
      >
        <ClipboardList size={16} /> Ver historial de días guardados
      </button>

      <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 10, marginBottom: 20 }}>
        <SummaryCard label="ENTRADAS DE HOY" value={totalEntradas} color="#4ade80" Icon={ArrowDown} />
        <SummaryCard label="SALIDAS DE HOY" value={totalSalidas} color="#f87171" Icon={ArrowUp} />
      </div>

      {insumos.map((i) => {
        const stat = statFor(i.id);
        const quedan = Math.max(0, i.stock - stat.salidas);
        const confirming = confirmDeleteId === i.id;
        return (
          <div key={i.id} style={{ background: "#141414", borderRadius: 16, padding: 16, marginBottom: 14 }}>
            <div style={{ display: "flex", alignItems: "center", gap: 12, marginBottom: 14 }}>
              {isImageSrc(i.icon) ? (
                <img src={i.icon} alt={i.name} style={{ width: 46, height: 46, borderRadius: 12, objectFit: "cover", flexShrink: 0 }} />
              ) : (
                <span style={{ fontSize: 34, flexShrink: 0 }}>{i.icon || "📦"}</span>
              )}
              <div style={{ fontWeight: 700, fontSize: 17, lineHeight: 1.25 }}>{i.name}</div>
            </div>

            <div style={{ display: "flex", gap: 10 }}>
              <Stepper
                color="#4ade80"
                bg="#2f6b46"
                value={i.stock}
                caption="en bodega"
                subCaption={`Quedan: ${quedan}`}
                onDec={() => bumpEntrada(i, -1)}
                onInc={() => bumpEntrada(i, 1)}
              />
              <Stepper
                color="#f87171"
                bg="#7a3030"
                value={stat.salidas}
                caption="salidas hoy"
                subCaption={`Total salidas: ${stat.salidas}`}
                onDec={() => bumpSalida(i, -1)}
                onInc={() => bumpSalida(i, 1)}
              />
            </div>

            <div style={{ display: "flex", justifyContent: "center", gap: 18, marginTop: 12 }}>
              <button onClick={() => setEditing(i)} style={{ background: "none", border: "none", color: "#999", fontSize: 13, display: "flex", alignItems: "center", gap: 5 }}>
                <Pencil size={13} /> Editar
              </button>
              {confirming ? (
                <>
                  <button
                    onClick={async () => {
                      await saveInsumos(insumos.filter((x) => x.id !== i.id));
                      setConfirmDeleteId(null);
                    }}
                    style={{ background: "none", border: "none", color: "#f87171", fontSize: 13, fontWeight: 700 }}
                  >
                    Sí, borrar
                  </button>
                  <button onClick={() => setConfirmDeleteId(null)} style={{ background: "none", border: "none", color: "#999", fontSize: 13 }}>
                    Cancelar
                  </button>
                </>
              ) : (
                <button onClick={() => setConfirmDeleteId(i.id)} style={{ background: "none", border: "none", color: "#999", fontSize: 13, display: "flex", alignItems: "center", gap: 5 }}>
                  <Trash2 size={13} /> Eliminar
                </button>
              )}
            </div>
          </div>
        );
      })}

      {savedMessage && (
        <div style={{ background: "#12241a", border: "1px solid #2f6b46", color: "#4ade80", borderRadius: 12, padding: "14px 16px", fontSize: 14, fontWeight: 600, textAlign: "center", marginBottom: 14 }}>
          ✓ {savedMessage}
        </div>
      )}

      <button
        onClick={closeDay}
        style={{ width: "100%", background: "#22c55e", border: "none", borderRadius: 14, padding: "18px", color: "#fff", fontWeight: 800, fontSize: 17, display: "flex", alignItems: "center", justifyContent: "center", gap: 10, marginTop: 6 }}
      >
        <Check size={20} /> Guardar y actualizar bodega
      </button>
      <div style={{ color: "#888", fontSize: 13, textAlign: "center", marginTop: 10 }}>
        Esto deja en bodega lo que quedó de cada insumo y pone los contadores de hoy en cero.
      </div>
    </div>
  );
}

function InventoryHistoryView({ historial, onBack }) {
  const sorted = [...historial].sort((a, b) => (a.dateKey < b.dateKey ? 1 : -1));

  return (
    <div style={{ padding: "16px 18px" }}>
      <div style={{ display: "flex", alignItems: "center", gap: 10, marginBottom: 16 }}>
        <button onClick={onBack} style={{ background: "#1a1a1a", border: "none", borderRadius: 10, width: 40, height: 40, color: "#fff", display: "flex", alignItems: "center", justifyContent: "center", flexShrink: 0 }}>
          <ChevronLeft size={24} />
        </button>
        <h2 style={{ margin: 0, fontSize: 19 }}>Historial de inventario</h2>
      </div>

      {sorted.length === 0 && (
        <div style={{ color: "#666", textAlign: "center", padding: "40px 0", fontSize: 15 }}>
          Todavía no has guardado ningún día. Usa "Guardar y actualizar bodega" para empezar a ver tu historial aquí.
        </div>
      )}

      {sorted.map((rec) => {
        const dateObj = new Date(rec.dateKey + "T00:00:00");
        const label = dateObj.toLocaleDateString("es-CO", { weekday: "long", day: "numeric", month: "long", year: "numeric" });
        const labelCap = label.charAt(0).toUpperCase() + label.slice(1);
        const totalE = rec.items.reduce((s, it) => s + it.entradas, 0);
        const totalS = rec.items.reduce((s, it) => s + it.salidas, 0);
        return (
          <div key={rec.id} style={{ background: "#141414", borderRadius: 16, padding: 16, marginBottom: 14 }}>
            <div style={{ fontWeight: 700, fontSize: 16, marginBottom: 4 }}>{labelCap}</div>
            <div style={{ color: "#999", fontSize: 13, marginBottom: 12 }}>
              <span style={{ color: "#4ade80", fontWeight: 700 }}>+{totalE} entradas</span>{"  ·  "}
              <span style={{ color: "#f87171", fontWeight: 700 }}>-{totalS} salidas</span>
            </div>
            {rec.items.map((it) => (
              <div key={it.insumoId} style={{ display: "flex", alignItems: "center", gap: 10, padding: "8px 0", borderTop: "1px solid #222" }}>
                {isImageSrc(it.icon) ? (
                  <img src={it.icon} alt={it.name} style={{ width: 32, height: 32, borderRadius: 8, objectFit: "cover" }} />
                ) : (
                  <span style={{ fontSize: 22 }}>{it.icon || "📦"}</span>
                )}
                <div style={{ flex: 1, minWidth: 0 }}>
                  <div style={{ fontWeight: 600, fontSize: 14 }}>{it.name}</div>
                  <div style={{ color: "#888", fontSize: 12 }}>Quedaron {it.quedan} {it.unit}</div>
                </div>
                <div style={{ textAlign: "right" }}>
                  {it.entradas > 0 && <div style={{ color: "#4ade80", fontWeight: 700, fontSize: 13 }}>+{it.entradas}</div>}
                  {it.salidas > 0 && <div style={{ color: "#f87171", fontWeight: 700, fontSize: 13 }}>-{it.salidas}</div>}
                </div>
              </div>
            ))}
          </div>
        );
      })}
    </div>
  );
}

